    def converter_pontos_em_faixa_iegm(pontos):
        pts = float(pontos)
        if pts <= 500:       return "C"
        elif pts <= 599:     return "C+"
        elif pts <= 749:     return "B"
        elif pts <= 899:     return "B+"
        else:                return "A"

