                # Proporções (Qi)
                q1 = f1 / total_escolas
                q2 = f2 / total_escolas
                q3 = f3 / total_escolas
                q4 = f4 / total_escolas
                q5 = f5 / total_escolas
                q6 = f6 / total_escolas
                
