                soma = (
                    int(st.session_state.get(k_q15_faixa1, v_t1)) +
                    int(st.session_state.get(k_q15_faixa2, v_t2)) +
                    int(st.session_state.get(k_q15_faixa3, v_t3)) +
                    int(st.session_state.get(k_q15_faixa4, v_t4))
                )
                st.session_state[k_q15_total] = soma

