        with st.expander(f"🔍 QUESITO 2.4 - Formação dos Professores de Pré-escola ({ano_sel})", expanded=True):
            st.markdown('<div class="quesito-card">', unsafe_allow_html=True)
            st.markdown("#### QUESITO 2.4")
            st.write(f"**Informe os dados sobre a formação dos professores regentes de Pré-escola (Efetivos e Temporários - Censo Escolar 2025) em {ano_sel}:**")
            st.markdown("""
            *Regras de Pontuação ($Pmáx = 18$ pontos):*
            * **N1 (Licenciatura - G):** $100\\% = 11$ pts | $90\\%$ a $99.9\\% = 7$ pts | $80\\%$ a $89.9\\% = 3$ pts | $70\\%$ a $79.9\\% = 1$ pt | $< 70\\% = 0$ pts
            * **N2 (Pós-Graduação - P):** $\ge 50\\% = 7$ pts | $40\\%$ a $49.9\\% = 5$ pts | $20\\%$ a $39.9\\% = 3$ pts | $< 20\\% = 0$ pts
            * **Nota Final:** $NF = N1 + N2$
            """)
            st.caption("ℹ️ *Os cálculos e salvamento ocorrem em tempo real ao alterar os valores.*")
            
            d24 = res_data.get("2.4", {"valor": "GRAD:0,PGRAD:0,TOTAL:0", "pontos": 0.0, "link": ""})
            v_banco_24 = d24.get("valor", "GRAD:0,PGRAD:0,TOTAL:0")
            v_link_24 = d24.get("link", "")
            
            # Tratamento seguro de split para ler os dados do banco
            try:
                parts_24 = v_banco_24.split(",")
                v_grad_24 = 0
                v_pgrad_24 = 0
                v_total_24 = 0
                for part in parts_24:
                    if "GRAD" in part and "PGRAD" not in part: v_grad_24 = int(part.split(":")[1])
                    if "PGRAD" in part: v_pgrad_24 = int(part.split(":")[1])
                    if "TOTAL" in part: v_total_24 = int(part.split(":")[1])
            except:
                v_grad_24, v_pgrad_24, v_total_24 = 0, 0, 0

            # Definição das chaves do Session State únicas para o 2.4
            k_grad_24 = f"q24_grad_{ano_sel}"
            k_total_24 = f"q24_total_manual_{ano_sel}"
            k_pgrad_24 = f"q24_pgrad_{ano_sel}"
            k_link_24 = f"link_q24_txt_val_{ano_sel}"

            if k_grad_24 not in st.session_state: st.session_state[k_grad_24] = v_grad_24
            if k_total_24 not in st.session_state: st.session_state[k_total_24] = v_total_24
            if k_pgrad_24 not in st.session_state: st.session_state[k_pgrad_24] = v_pgrad_24
            if k_link_24 not in st.session_state: st.session_state[k_link_24] = v_link_24

            # Função interna para cálculo dinâmico da nota matemática
            def calcular_nota_com_valores_24(g_val, t_val, p_val):
                if t_val <= 0:
                    return 0.0
                
                # N1 (Graduação)
                g_perc = min(1.0, g_val / t_val)
                if g_perc >= 1.0: n1 = 11.0
                elif g_perc >= 0.90: n1 = 7.0
                elif g_perc >= 0.80: n1 = 3.0
                elif g_perc >= 0.70: n1 = 1.0
                else: n1 = 0.0
                
                # N2 (Pós-Graduação)
                p_perc = min(1.0, p_val / t_val)
                if p_perc >= 0.50: n2 = 7.0
                elif p_perc >= 0.40: n2 = 5.0
                elif p_perc >= 0.20: n2 = 3.0
                else: n2 = 0.0
                
