            # PROCESSAMENTO MATEMÁTICO ISOLADO EM CALLBACK (Fim do loop infinito)
            def processar_e_salvar_31():
                try:
                    int_f1 = int(st.session_state[key_f1_31].strip()) if st.session_state[key_f1_31].strip() != "" else 0
                    int_f2 = int(st.session_state[key_f2_31].strip()) if st.session_state[key_f2_31].strip() != "" else 0
                    int_f3 = int(st.session_state[key_f3_31].strip()) if st.session_state[key_f3_31].strip() != "" else 0
                    int_f4 = int(st.session_state[key_f4_31].strip()) if st.session_state[key_f4_31].strip() != "" else 0
                except:
                    int_f1, int_f2, int_f3, int_f4 = 0, 0, 0, 0
                    
                total_turmas = int_f1 + int_f2 + int_f3 + int_f4
                
                if total_turmas > 0:
                    pts_calculados = round((10.0 * (int_f1 / total_turmas)) + (5.0 * (int_f2 / total_turmas)) + (2.5 * (int_f3 / total_turmas)), 2)
                else:
                    pts_calculados = 0.0
                    
                str_valor_novo = f"F1:{int_f1},F2:{int_f2},F3:{int_f3},F4:{int_f4}"
                link_atual = st.session_state.get(key_link_31, "")
                
                if str_valor_novo != str(v_banco_31) or link_atual != v_link_31 or v_pontos_31 != pts_calculados:
                    if link_atual != v_link_31:
                        links_f31 = re.findall(r'(https?://[^\s]+)', link_atual)
                        links_31_antigos = re.findall(r'(https?://[^\s]+)', v_link_31)
                        if links_f31 and links_f31 != links_31_antigos:
                            st.session_state[f"trigger_modal_31_{ano_sel}"] = True
                            
                    save_resp("3.1", str_valor_novo, float(pts_calculados), link_atual)
