                grad = st.number_input("Q32_GRAD", min_value=0, step=1, value=v_grad, key=f"q32_grad_{ano_sel}", label_visibility="collapsed")
                
                st.markdown('<label style="font-size: 13px; font-weight: 500;">Possuem Pós-graduação (PGRAD):</label>', unsafe_allow_html=True)
