        # --- QUESITO 7.0 (Programa de Inibição ao Absenteísmo) ---
        with st.expander(f"🔍 QUESITO 7.0 - Programa de Inibição ao Absenteísmo ({ano_sel})", expanded=True):
            st.markdown('<div class="quesito-card">', unsafe_allow_html=True)
            st.markdown("#### QUESITO 7.0")
            st.write("**Existe um programa de inibição ao absenteísmo de professores in sala de aula (incluindo os afastamentos legais)?**")
            
            d70_dados = res_data.get("7.0", {"valor": "", "pontos": 0.0, "link": ""})
            v_banco_70 = d70_dados.get("valor", "")
            v_link_70 = d70_dados.get("link", "")
            
            opc70 = [
                "Selecione...",
                "Sim – 05",
                "Não – 00"
            ]
            
            key_radio_70 = f"q70_absent_{ano_sel}"
            if key_radio_70 not in st.session_state:
                st.session_state[key_radio_70] = v_banco_70 if v_banco_70 in opc70 else "Selecione..."

            key_link_70 = f"link_q70_txt_val_{ano_sel}"
            if key_link_70 not in st.session_state:
                st.session_state[key_link_70] = v_link_70

            # Resgate seguro das variáveis de auditoria
            v_calc_70 = st.session_state.get(f"v_calc_70_{ano_sel}", "Q1:NÃO,Q2:NÃO,Q3:NÃO,QTA_A:0,PROF_A:1,QTA_B:0,PROF_B:1,QTA_C:0,PROF_C:1")
            try:
                p_c = dict(item.split(":") for item in v_calc_70.split(","))
            except:
                p_c = {"Q1":"NÃO","Q2":"NÃO","Q3":"NÃO","QTA_A":"0","PROF_A":"1","QTA_B":"0","PROF_B":"1","QTA_C":"0","PROF_C":"1"}

            q1_sel = st.session_state.get(f"q70_q1_{ano_sel}", p_c.get("Q1", "NÃO"))
            qta_a = st.session_state.get(f"q70_v_qta_a_{ano_sel}", int(p_c.get("QTA_A", 0)))
            prof_a = st.session_state.get(f"q70_v_prof_a_{ano_sel}", int(p_c.get("PROF_A", 1)))

            q2_sel = st.session_state.get(f"q70_q2_{ano_sel}", p_c.get("Q2", "NÃO"))
            qta_b = st.session_state.get(f"q70_v_qta_b_{ano_sel}", int(p_c.get("QTA_B", 0)))
            prof_b = st.session_state.get(f"q70_v_prof_b_{ano_sel}", int(p_c.get("PROF_B", 1)))

            q3_sel = st.session_state.get(f"q70_q3_{ano_sel}", p_c.get("Q3", "NÃO"))
            qta_c = st.session_state.get(f"q70_v_qta_c_{ano_sel}", int(p_c.get("QTA_C", 0)))
            prof_c = st.session_state.get(f"q70_v_prof_c_{ano_sel}", int(p_c.get("PROF_C", 1)))

            taxa_a = ((qta_a / prof_a) * 100) if prof_a > 0 else 0.0
            taxa_b = ((qta_b / prof_b) * 100) if prof_b > 0 else 0.0
            taxa_c = ((qta_c / prof_c) * 100) if prof_c > 0 else 0.0

            # FUNÇÃO DE CÁLCULO RESTRITA E CORRIGIDA
            def calcular_pontos_totais_70(opcao_selecionada):
                if opcao_selecionada != "Sim – 05":
                    return 0.0
                
                # Só calcula deduções se for SIM
                na_c, nb_c, nc_c = 0.0, 0.0, 0.0
                if q1_sel == "SIM" and q2_sel == "SIM" and q3_sel == "SIM":
                    na_c = -1.5 if taxa_a > 10 else 0.0
                    nb_c = -1.5 if taxa_b > 10 else 0.0
                    nc_c = -2.0 if taxa_c > 10 else 0.0
                elif q1_sel == "NÃO" and q2_sel == "SIM" and q3_sel == "SIM":
                    nb_c = -2.5 if taxa_b > 10 else 0.0
                    nc_c = -2.5 if taxa_c > 10 else 0.0
                elif q1_sel == "SIM" and q2_sel == "NÃO" and q3_sel == "SIM":
                    na_c = -2.5 if taxa_a > 10 else 0.0
                    nc_c = -2.5 if taxa_c > 10 else 0.0
                elif q1_sel == "SIM" and q2_sel == "SIM" and q3_sel == "NÃO":
                    na_c = -2.5 if taxa_a > 10 else 0.0
                    nb_c = -2.5 if taxa_b > 10 else 0.0
                elif q1_sel == "NÃO" and q2_sel == "NÃO" and q3_sel == "SIM":
                    nc_c = -5.0 if taxa_c > 10 else 0.0
                elif q1_sel == "NÃO" and q2_sel == "SIM" and q3_sel == "NÃO":
                    nb_c = -5.0 if taxa_b > 10 else 0.0
                elif q1_sel == "SIM" and q2_sel == "NÃO" and q3_sel == "NÃO":
                    na_c = -5.0 if taxa_a > 10 else 0.0
                    
                return round(5.0 + na_c + nb_c + nc_c, 2)

            def callback_radio_70():
                novo_val = st.session_state[key_radio_70]
                valor_salvar = novo_val if novo_val != "Selecione..." else ""
                
                if valor_salvar != v_banco_70:
                    pts = calcular_pontos_totais_70(novo_val)
                    save_resp("7.0", valor_salvar, pts, st.session_state[key_link_70])
                    res_data["7.0"] = {"valor": valor_salvar, "pontos": pts, "link": st.session_state[key_link_70]}

            def callback_link_70():
                novo_link = st.session_state[key_link_70]
                if novo_link != v_link_70:
                    valor_atual = st.session_state[key_radio_70]
                    valor_salvar = valor_atual if valor_atual != "Selecione..." else ""
                    pts = calcular_pontos_totais_70(valor_atual)
                    
                    save_resp("7.0", valor_salvar, pts, novo_link)
