            st.caption("Insira o número total de alunos da rede municipal e a quantidade de profissionais para calcular a conformidade.")

            d81_dados = res_data.get("8.1", {"valor": "", "pontos": 0.0, "link": ""})
            v_banco_81 = d81_dados.get("valor", "")
            v_link_81 = d81_dados.get("link", "")

