                t_al = st.session_state[f"q81_alunos_{ano_sel}"]
                n_serv = st.session_state[f"q81_serv_{ano_sel}"]
                n_terc = st.session_state[f"q81_terc_{ano_sel}"]
                qi_t = n_serv + n_terc
                
                if t_al <= 500:
                    exig = 1
                elif t_al <= 1000:
                    exig = 2
                elif t_al <= 2500:
                    exig = 3
                elif t_al <= 5000:
                    exig = 4
                else:
                    exig = 4 + ((t_al - 5000 + 2499) // 2500)
                
                pts = 12.0 if (t_al > 0 and qi_t >= exig) else 0.0
                str_salvar = f"Alunos: {t_al} | Servidores: {n_serv} | Terceirizados: {n_terc} | Total: {qi_t}"
                
                save_resp("8.1", str_salvar, pts, st.session_state[key_link_81])
                res_data["8.1"] = {"valor": str_salvar, "pontos": pts, "link": st.session_state[key_link_81]}

