                    p_max = 18.0
                    total_publico_alvo = q_presentes_5ano + q_ausentes_5ano

                    if total_publico_alvo > 0:
                        # P1 = Alunos Presentes / Total de Alunos (Presentes + Ausentes)
                        p1_percentual = q_presentes_5ano / total_publico_alvo
