                # E11 • Mínimo Constitucional em Educação (Dados AUDESP)
                # =============================================================================
                st.markdown("---")
                st.subheader("E11 • Aplicação do Mínimo Constitucional em Educação")
                st.write("**Mede a aplicação do limite mínimo constitucional de 25% em educação (Ensino com recursos próprios sobre receita de impostos)**")

                # Tabela de Regras de Pontuação (Regras de Rebaixamento de Nota)
                st.markdown(r"""
                | Resultado do Índice $PE$ | Impacto / Pontuação do Indicador |
                | :--- | :--- |
                | Maior ou igual a 25% ($PE \ge 25\%$) | ✅ 00 ponto (Cumpre o Mínimo Constitucional / Sem Penalidade) |
                | Menor que 25% ($PE < 25\%$) | 🚨 REBAIXAR 1 faixa do i-Educ (Descumprimento do Art. 212 da CF) |
                """)
                st.caption("ℹ️ *Variáveis parametrizadas e calculadas extraídas diretamente do Sistema AUDESP.*")

                # 🧹 Função de Higienização robusta baseada em caracteres numéricos puros
                def tratar_string_monetaria_para_float(texto):
                    if not texto: 
                        return 0.0
                    # Remove R$, espaços e pontos de milhar, mantendo apenas dígitos e a vírgula decimal
                    apenas_numeros = "".join(c for c in texto if c.isdigit() or c == ",")
                    if "," in apenas_numeros:
                        apenas_numeros = apenas_numeros.replace(",", ".")
                    try:
                        return float(apenas_numeros)
                    except ValueError:
                        return 0.0

                # 🎨 Função de formatação limpa padrão BR
                def formatar_para_moeda_br(valor_float):
                    return f"R$ {valor_float:,.2f}".replace(",", "X").replace(".", ",").replace("X", ".")

                # Carrega ou inicializa a string persistida no banco contendo a dupla de valores (DESP/REC)
                dE11 = res_data.get("E11", {"valor": "0.00/1.00", "pontos": 0.0, "link": ""})

                try:
                    val_salvo_desp, val_salvo_rec = dE11["valor"].split("/")
                    float_desp = float(val_salvo_desp)
                    float_rec = float(val_salvo_rec)
                except:
                    float_desp, float_rec = 0.0, 1.0

                # Garante que o session_state inicialize no formato correto do Brasil
                if f"e11_str_desp_{ano_sel}" not in st.session_state:
                    st.session_state[f"e11_str_desp_{ano_sel}"] = formatar_para_moeda_br(float_desp)
                if f"e11_str_rec_{ano_sel}" not in st.session_state:
                    st.session_state[f"e11_str_rec_{ano_sel}"] = formatar_para_moeda_br(float_rec)

                c1, c2 = st.columns([1, 2])

                with c1:
                    # Input 1: Despesa aplicada em Ensino (DESP)
                    input_desp_str = st.text_input(
                        "Despesa em Ensino com Recursos Próprios (DESP) - R$:",
                        value=st.session_state[f"e11_str_desp_{ano_sel}"],
                        placeholder="Ex: 10.000,00",
                        key=f"txt_e11_desp_dinamico_{ano_sel}"
                    )
                    
                    # Input 2: Receita de Impostos (REC)
                    input_rec_str = st.text_input(
                        "Receita de Impostos Próprios / Transferências (REC) - R$:",
                        value=st.session_state[f"e11_str_rec_{ano_sel}"],
                        placeholder="Ex: 2.500,00",
                        key=f"txt_e11_rec_dinamico_{ano_sel}"
                    )

                    # Conversão segura usando o novo motor limpo
                    v_desp = tratar_string_monetaria_para_float(input_desp_str)
                    v_rec = tratar_string_monetaria_para_float(input_rec_str)

                    # Sincroniza o session_state formatando de forma correta e sem duplicar máscaras
                    st.session_state[f"e11_str_desp_{ano_sel}"] = formatar_para_moeda_br(v_desp)
                    st.session_state[f"e11_str_rec_{ano_sel}"] = formatar_para_moeda_br(v_rec)

                    # 🧮 Correção da Fórmula: Despesa dividida pela Receita de Impostos
                    try:
                        base_calculo = max(v_rec, 0.01)
                        PE = round((v_desp / base_calculo) * 100.0, 2)
                    except:
                        PE = 0.0

                    # 🛑 TRAVA DE INICIALIZAÇÃO / CAMPOS ZERADOS
                    if v_desp == 0.0 and v_rec == 0.0:
                        ptsE11 = 0.0
                        texto_resultado = "Aguardando preenchimento dos valores faturados..."
                        texto_pontuacao = "⏳ Sem avaliação"
                        estilo_status = "color: #64748b;"
                    else:
                        # 🧮 MOTOR DE REGRAS DO IEGM (Abaixo de 25% gera rebaixamento)
                        if PE >= 25.00:
                            ptsE11 = 0.0
                            texto_resultado = "✅ REGULAR: Município atende ao limite mínimo de 25% de aplicação constitucional em MDE"
                            texto_pontuacao = "0,00 pontos (Sem Penalidade)"
                            estilo_status = "color: #16a34a; font-weight: bold;"
                        else:
                            ptsE11 = 0.0
                            texto_resultado = "🚨 DESCUMPRIMENTO: Aplicação abaixo do mínimo de 25% estabelecido no Art. 212 da CF"
                            texto_pontuacao = "REBAIXAR 1 FAIXA DO i-EDUC"
                            estilo_status = "color: #dc2626; font-weight: bold;"

                with c2:
                    lE11 = st.text_area("Link/Evidência (E11 - Mínimo Constitucional Educação - AUDESP):", value=dE11.get("link", ""), key=f"txt_e11_{ano_sel}", height=150)

                # Gera a visualização final estritamente corrigida
                v_desp_br = formatar_para_moeda_br(v_desp)
                v_rec_br = formatar_para_moeda_br(v_rec)
                pe_br = f"{PE:.2f}".replace(".", ",")

                # Exibição do painel consolidador utilizando st.info/st.error para manter a UI limpa e nativa
                if v_desp == 0.0 and v_rec == 0.0:
                    st.info(f"📌 **Valores Processados:** {v_desp_br} / {v_rec_br}\n\n{texto_resultado}")
                elif PE >= 25.00:
                    st.info(
                        f"📌 **Valores Processados:** {v_desp_br} / {v_rec_br}\n"
                        f"📊 **Percentual de Aplicação (PE):** {pe_br}%\n"
                        f"⚖️ **Situação da Educação:** {texto_resultado}\n"
                        f"🎯 **Glosa/Impacto na Pontuação:** {texto_pontuacao}"
                    )
                else:
                    st.error(
                        f"📌 **Valores Processados:** {v_desp_br} / {v_rec_br}\n"
                        f"📊 **Percentual de Aplicação (PE):** {pe_br}%\n"
                        f"⚖️ **Situação da Educação:** {texto_resultado}\n"
                        f"🎯 **Glosa/Impacto na Pontuação:** {texto_pontuacao}"
                    )

                # Salva no banco separando os decimais puros por barra
                str_concatenada_e11 = f"{v_desp:.2f}/{v_rec:.2f}"

                if v_desp != float_desp or v_rec != float_rec or lE11 != dE11.get("link", ""):
                    save_resp("E11", str_concatenada_e11, ptsE11, lE11)
                    st.rerun()

                bloco_comentarios("E11", res_data)




